import React, { useEffect, useState } from 'react';
import { drawBloodPressureChart } from '../components/BloodPressureChart';

const Dashboard = () => {
  const [patients, setPatients] = useState([]);

  // Fetch patient data from the API
  useEffect(() => {
    const fetchPatients = async () => {
      const apiUrl = 'https://fedskillstest.coalitiontechnologies.workers.dev/patients';
      const username = process.env.REACT_APP_API_USERNAME;
      const password = process.env.REACT_APP_API_PASSWORD;

      const headers = new Headers();
      headers.set('Authorization', 'Basic ' + btoa(`${username}:${password}`));

      try {
        const response = await fetch(apiUrl, { headers });
        if (!response.ok) {
          throw new Error('Failed to fetch patient data');
        }
        const data = await response.json();
        const patientArray = Array.isArray(data) ? data : [];
        setPatients(patientArray);  
        updatePatientListInHTML(patientArray);
      } catch (error) {
        console.error('Error:', error);
        setPatients([]);
        updatePatientListInHTML([]);
      }
    };

    fetchPatients();
  }, []);

  // Function to update the patient list in the plain HTML
  const updatePatientListInHTML = (patients) => {
    const patientListElement = document.getElementById('patient-list');
    if (!patientListElement) return;

    // Clear existing content
    patientListElement.innerHTML = '';

    // If no patients, show a message
    if (!Array.isArray(patients) || patients.length === 0) {
      patientListElement.innerHTML = '<li>No patients data available</li>';
      return;
    }

    // Loop through each patient and create list items
    patients.forEach((patient) => {
      const { name, gender, age, profile_picture } = patient;

      // Create list item
      const listItem = document.createElement('li');
      listItem.className = 'patient';
      listItem.style.cursor = 'pointer';

      // Add click event to display the blood pressure chart for the selected patient
      listItem.addEventListener('click', () => {
        renderBloodPressureChartInHTML(patient);
      });

      // Create image
      const img = document.createElement('img');
      img.src = profile_picture;
      img.alt = `Profile picture of ${name}`;
      img.className = 'patient-photo';

      // Create info div
      const infoDiv = document.createElement('div');
      infoDiv.className = 'patient-info';

      // Create name span
      const nameSpan = document.createElement('span');
      nameSpan.className = 'patient-name';
      nameSpan.textContent = name;

      // Create details span
      const detailsSpan = document.createElement('span');
      detailsSpan.className = 'patient-details';
      detailsSpan.textContent = `${gender}, ${age}`;

      // Append elements
      infoDiv.appendChild(nameSpan);
      infoDiv.appendChild(detailsSpan);
      listItem.appendChild(img);
      listItem.appendChild(infoDiv);

      // Append list item to the HTML patient list
      patientListElement.appendChild(listItem);
    });
  };

  // Function to render the blood pressure chart in the HTML
  const renderBloodPressureChartInHTML = (patient) => {
    const { name, bloodPressureData, diagnosis_history, respiratoryRate, temperature, heartRate } = patient;

    // Update chart title
    const chartTitle = document.getElementById('chart-title');
    if (chartTitle) {
      chartTitle.textContent = `Blood Pressure Chart for ${name}`;
    }

    // Check for diagnosis history
    const latestDiagnosis = diagnosis_history?.[0];
    if (!latestDiagnosis) {
      console.error('No diagnosis data available');
      return;
    }

    // Extract systolic and diastolic data from bloodPressureData
    const systolicData = bloodPressureData?.systolic || [];
    const diastolicData = bloodPressureData?.diastolic || [];
    const labels = ["Oct 2023", "Nov 2023", "Dec 2023", "Jan 2024", "Feb 2024", "Mar 2024"];

    // Use the latest available data point or set as 'N/A'
    const latestSystolic = systolicData?.slice(-1)[0] || 'N/A';
    const latestDiastolic = diastolicData?.slice(-1)[0] || 'N/A';
    const respiratory = respiratoryRate || 'N/A';
    const temp = temperature || 'N/A';
    const hr = heartRate || 'N/A';

    // Update HTML with metrics
    document.querySelector('.stats .stat:nth-child(1) span').textContent = `${latestSystolic} mmHg`;
    document.querySelector('.stats .stat:nth-child(2) span').textContent = `${latestDiastolic} mmHg`;
    document.querySelector('.health-metrics .metric:nth-child(1) p').textContent = `${respiratory} bpm`;
    document.querySelector('.health-metrics .metric:nth-child(2) p').textContent = `${temp}°F`;
    document.querySelector('.health-metrics .metric:nth-child(3) p').textContent = `${hr} bpm`;

    // Update Heart Rate Status
    const heartRateStatusElement = document.querySelector('.health-metrics .metric:nth-child(3) span');
    if (hr < 60) {
      heartRateStatusElement.textContent = 'Lower than Average';
    } else if (hr > 100) {
      heartRateStatusElement.textContent = 'Higher than Average';
    } else {
      heartRateStatusElement.textContent = 'Normal';
    }

    // Draw the blood pressure chart
    drawBloodPressureChart(systolicData, diastolicData, labels);
  };

  return null;
};

export default Dashboard;
