import {
  Chart,
  LineController,
  LineElement,
  PointElement,
  LinearScale,
  Title,
  CategoryScale,
  Legend,
  Tooltip,
  Filler,
} from 'chart.js';

// Register components
Chart.register(LineController, LineElement, PointElement, LinearScale, Title, CategoryScale, Legend, Tooltip, Filler);

// Store a reference to the chart instance
let bloodPressureChartInstance = null;

// Function to draw the blood pressure chart
export const drawBloodPressureChart = (systolicData, diastolicData, labels) => {
  const ctx = document.getElementById('bloodPressureChart');
  if (!ctx) return;

  // Destroy the existing chart instance if it exists
  if (bloodPressureChartInstance) {
    bloodPressureChartInstance.destroy();
  }

  // Create a new chart instance
  bloodPressureChartInstance = new Chart(ctx, {
    type: 'line',
    data: {
      labels: labels,
      datasets: [
        {
          label: 'Systolic',
          data: systolicData,
          borderColor: 'rgba(255, 99, 132, 1)',
          backgroundColor: 'rgba(255, 99, 132, 0.2)',
          borderWidth: 2,
          fill: true,
          tension: 0.4,
        },
        {
          label: 'Diastolic',
          data: diastolicData,
          borderColor: 'rgba(54, 162, 235, 1)',
          backgroundColor: 'rgba(54, 162, 235, 0.2)',
          borderWidth: 2,
          fill: true,
          tension: 0.4,
        },
      ],
    },
    options: {
      responsive: false, // Disable responsive resizing
      maintainAspectRatio: false, // Allow for fixed width and height
      scales: {
        x: {
          type: 'category',
          title: {
            display: true,
            text: 'Months',
          },
        },
        y: {
          type: 'linear',
          beginAtZero: false,
          suggestedMin: 60,
          suggestedMax: 180,
          title: {
            display: true,
            text: 'Blood Pressure (mmHg)',
          },
        },
      },
      plugins: {
        legend: {
          position: 'top',
        },
        tooltip: {
          enabled: true,
        },
      },
    },
  });
};
